  const [viewDrawerOpen, setViewDrawerOpen] = useState(false)
  const [viewingStaff, setViewingStaff] = useState<Staff | null>(null)

  const { data: branches } = useBranchesQuery()
  const { data: staffs, isLoading } = useStaffsQuery(
    filterBranchId || undefined,
  )
  const createMutation = useCreateStaffMutation()
  const editMutation = useEditStaffMutation()
  const deleteMutation = useDeleteStaffsMutation()

  const filteredStaffs = staffs?.filter(
    (s: Staff) =>
      s.fullname.toLowerCase().includes(search.toLowerCase()) ||
      s.email?.toLowerCase().includes(search.toLowerCase()),
  )

  const openCreate = () => {
    setEditingStaff(null)
    setForm({ ...emptyForm, branchId: filterBranchId || '' })
    setDrawerOpen(true)
  }

  const openEdit = (staff: Staff) => {
    setEditingStaff(staff)
    setForm({
      branchId: staff.branchId,
      fullname: staff.fullname,
      email: staff.email || '',
      phone: staff.phone,
      roles: staff.roles || 'TEACHER',
    })
    setDrawerOpen(true)
  }

  const openView = (staff: Staff) => {
    setViewingStaff(staff)
    setViewDrawerOpen(true)
  }

  const handleSave = () => {
    if (!form.fullname.trim() || !form.branchId) return

    if (editingStaff) {
      editMutation.mutate(
        { staffId: editingStaff.id, data: form },
        {
          onSuccess: () => {
            toast.success('Staff updated')
            setDrawerOpen(false)
          },
          onError: (err: any) =>
            toast.error(err?.message || 'Failed to update'),
        },
      )
    } else {
      createMutation.mutate(form, {
        onSuccess: () => {
          toast.success('Staff created')
          setDrawerOpen(false)
        },
        onError: (err: any) => toast.error(err?.message || 'Failed to create'),
      })
    }
  }

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return

    deleteMutation.mutate(selectedIds, {
      onSuccess: () => {
        toast.success(`${selectedIds.length} staff member(s) deleted`)
        setSelectedIds([])
        setDeleteConfirmOpen(false)
      },
      onError: (err: any) => {
        toast.error(err?.message || 'Failed to delete')
        setDeleteConfirmOpen(false)
      },
    })
  }

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id],
    )
  }

  const toggleSelectAll = () => {
    if (!filteredStaffs) return
    if (selectedIds.length === filteredStaffs.length) {
      setSelectedIds([])
    } else {
      setSelectedIds(filteredStaffs.map((s: Staff) => s.id))
    }
  }

  const isPending = createMutation.isPending || editMutation.isPending

  const updateField = (field: keyof CreateStaffDTO, value: string) =>
    setForm((prev) => ({ ...prev, [field]: value }))

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Staff / Teachers</h1>
        <p className="text-muted-foreground text-sm">
          Manage staff members across your school branches
        </p>
      </div>

      {/* Controls */}
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <CustomSelect
            fieldClassName="w-[260px]"
            value={filterBranchId}
            onValueChange={(value) => {
              setFilterBranchId(value)
              setSelectedIds([])
            }}
            items={[
              { label: 'All branches', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
          <Input
            placeholder="Search staff..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="h-9 w-[220px]"
          />
        </div>
        <div className="flex items-center gap-2">
          {selectedIds.length > 0 && (
            <AlertDialog
              open={deleteConfirmOpen}
              onOpenChange={setDeleteConfirmOpen}
            >
              <AlertDialogTrigger asChild>
                <Button
                  variant="destructive"
                  size="sm"
                  disabled={deleteMutation.isPending}
                >
                  {deleteMutation.isPending
                    ? 'Deleting...'
                    : `Delete (${selectedIds.length})`}
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
                  <AlertDialogDescription>
                    This action cannot be undone. This will permanently delete{' '}
                    {selectedIds.length} staff member(s) and remove their data
                    from our servers.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleBatchDelete}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Delete Staff
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          )}
          <Button onClick={openCreate}>+ Add Staff</Button>
        </div>
      </div>

      {/* Table */}
      {isLoading ? (
        <div className="space-y-3">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-14 w-full" />
          ))}
        </div>
      ) : filteredStaffs && filteredStaffs.length > 0 ? (
        <div className="rounded-lg border bg-card overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[40px]">
                  <input
                    type="checkbox"
                    checked={
                      filteredStaffs.length > 0 &&
                      selectedIds.length === filteredStaffs.length
                    }
                    onChange={toggleSelectAll}
                    className="size-4"
                  />
                </TableHead>
                <TableHead>Name</TableHead>
                <TableHead>Role</TableHead>
                <TableHead>Branch</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredStaffs.map((staff: Staff) => (
                <TableRow
                  key={staff.id}
                  data-state={
                    selectedIds.includes(staff.id) ? 'selected' : undefined
                  }
                >
                  <TableCell>
                    <input
                      type="checkbox"
                      checked={selectedIds.includes(staff.id)}
                      onChange={() => toggleSelect(staff.id)}
                      className="size-4"
                    />
                  </TableCell>
                  <TableCell className="font-medium">
                    {staff.fullname}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={
                        staff.roles === 'ADMIN' ? 'default' : 'secondary'
                      }
                    >
                      {staff.roles}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-muted-foreground text-sm">
                    {staff.branch?.name || '—'}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={
                        staff.status === 'ACTIVE' ? 'default' : 'destructive'
                      }
                    >
                      {staff.status}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openView(staff)}
                        title="View details"
                      >
                        <Eye className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openEdit(staff)}
                        title="Edit staff"
                      >
                        <Pencil className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
          <div className="text-muted-foreground border-t px-4 py-2 text-xs">
            {filteredStaffs.length} staff member
            {filteredStaffs.length !== 1 ? 's' : ''}
          </div>
        </div>
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground mb-4">
              {search
                ? 'No staff members match your search.'
                : 'No staff members yet. Add your first staff member.'}
            </p>
            {!search && (
              <Button variant="outline" onClick={openCreate}>
                + Add Staff
              </Button>
            )}
          </CardContent>
        </Card>
      )}

      {/* Create/Edit Drawer */}
      <AppDrawer
        open={drawerOpen}
        onOpenChange={setDrawerOpen}
        title={editingStaff ? 'Edit Staff' : 'New Staff Member'}
        description={
          editingStaff
            ? 'Update staff member details.'
            : 'Fill in the details to add a new staff member.'
        }
        footer={
          <>
            <Button
              onClick={handleSave}
              disabled={isPending || !form.fullname.trim() || !form.branchId}
            >
              {isPending
                ? 'Saving...'
                : editingStaff
                  ? 'Save Changes'
                  : 'Create Staff'}
            </Button>
            <Button variant="outline" onClick={() => setDrawerOpen(false)}>
              Cancel
            </Button>
          </>
        }
      >
        <div className="space-y-2">
          <CustomSelect
            label={
              <>
                Branch <span className="text-destructive">*</span>
              </>
            }
            value={form.branchId}
            onValueChange={(value) => updateField('branchId', value)}
            items={[
              { label: 'Select branch', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>
            Full Name <span className="text-destructive">*</span>
          </Label>
          <Input
            placeholder="e.g. John Doe"
            value={form.fullname}
            onChange={(e) => updateField('fullname', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>
            Email <span className="text-destructive">*</span>
          </Label>
          <Input
            type="email"
            placeholder="john@school.com"
            value={form.email}
            onChange={(e) => updateField('email', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>
            Phone <span className="text-destructive">*</span>
          </Label>
          <Input
            placeholder="080xxxxxxxx"
            value={form.phone}
            onChange={(e) => updateField('phone', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <CustomSelect
            label="Role"
            value={form.roles}
            onValueChange={(value) => updateField('roles', value)}
            items={[
              { label: 'Teacher', value: 'TEACHER' },
              { label: 'Admin', value: 'ADMIN' },
            ]}
          />
        </div>
      </AppDrawer>

      {/* View Drawer */}
      <AppDrawer
        open={viewDrawerOpen}
        onOpenChange={setViewDrawerOpen}
        title="Staff Details"
        description={`Full information for ${viewingStaff?.fullname}`}
        footer={
          <Button variant="outline" onClick={() => setViewDrawerOpen(false)}>
            Close
          </Button>
        }
      >
        {viewingStaff && (
          <div className="space-y-6 pb-8">
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Full Name
              </p>
              <p className="text-base">{viewingStaff.fullname}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Email Address
              </p>
              <p className="text-sm">{viewingStaff.email || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Phone Number
              </p>
              <p className="text-sm">{viewingStaff.phone || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">Role</p>
              <Badge
                variant={
                  viewingStaff.roles === 'ADMIN' ? 'default' : 'secondary'
                }
              >
                {viewingStaff.roles}
              </Badge>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Branch
              </p>
              <p className="text-sm">{viewingStaff.branch?.name || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Status
              </p>
              <Badge
                variant={
                  viewingStaff.status === 'ACTIVE' ? 'default' : 'destructive'
                }
              >
                {viewingStaff.status}
              </Badge>
            </div>
          </div>
        )}
      </AppDrawer>
    </div>
  )
}

import { useState } from 'react'
import { createFileRoute } from '@tanstack/react-router'
import {
  useStudentsQuery,
  useCreateStudentMutation,
  useEditStudentMutation,
  useReassignStudentMutation,
  useDeleteStudentsMutation,
} from '@/hooks/queries/student.queries'
import { useBranchesQuery } from '@/hooks/queries/branch.queries'
import { useClassesQuery } from '@/hooks/queries/class.queries'
import type { StudentItem, CreateStudentDTO } from '@/hooks/api/student.api'
import type { ClassItem } from '@/hooks/api/class.api'
import type { Branch } from '@repo/types'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent } from '@/components/ui/card'
import { Skeleton } from '@/components/ui/skeleton'
import { AppDrawer } from '@/components/ui/app-drawer'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog'
import { toast } from '@/lib/toast'
import { Pencil, Eye, ArrowRightLeft } from 'lucide-react'
import { CustomSelect } from '@/components/ui/custom-select'

export const Route = createFileRoute('/_authenticated/dashboard/students')({
  component: StudentsPage,
})

const emptyForm: CreateStudentDTO = {
  branchId: '',
  classId: '',
  fullname: '',
  regNumber: '',
  email: '',
  phone: '',
}

function StudentsPage() {
  const [search, setSearch] = useState('')
  const [filterBranchId, setFilterBranchId] = useState('')
  const [filterClassId, setFilterClassId] = useState('')
  const [selectedIds, setSelectedIds] = useState<Array<string>>([])

  // CRUD state
  const [drawerOpen, setDrawerOpen] = useState(false)
  const [editingStudent, setEditingStudent] = useState<StudentItem | null>(null)
  const [form, setForm] = useState<CreateStudentDTO>(emptyForm)
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false)

  // Reassign state
  const [reassignDrawerOpen, setReassignDrawerOpen] = useState(false)
  const [reassignStudentId, setReassignStudentId] = useState('')
  const [reassignStudentName, setReassignStudentName] = useState('')
  const [reassignBranchId, setReassignBranchId] = useState('')
  const [reassignClassId, setReassignClassId] = useState('')

  // View state
  const [viewDrawerOpen, setViewDrawerOpen] = useState(false)
  const [viewingStudent, setViewingStudent] = useState<StudentItem | null>(null)

  // Queries
  const { data: branches } = useBranchesQuery()
  const { data: students, isLoading } = useStudentsQuery(
    filterBranchId || undefined,
    filterClassId || undefined,
  )
  const { data: filterClasses } = useClassesQuery(filterBranchId || undefined)

  // Classes for the form drawer (based on form branchId)
  const { data: formClasses } = useClassesQuery(form.branchId || undefined)

  // Classes for the reassign drawer
  const { data: reassignClasses } = useClassesQuery(
    reassignBranchId || undefined,
  )

  // Mutations
  const createMutation = useCreateStudentMutation()
  const editMutation = useEditStudentMutation()
  const reassignMutation = useReassignStudentMutation()
  const deleteMutation = useDeleteStudentsMutation()

  const filteredStudents = students?.filter(
    (s: StudentItem) =>
      s.fullname.toLowerCase().includes(search.toLowerCase()) ||
      s.regNumber?.toLowerCase().includes(search.toLowerCase()) ||
      s.email?.toLowerCase().includes(search.toLowerCase()),
  )

  const openCreate = () => {
    setEditingStudent(null)
    setForm({ ...emptyForm, branchId: filterBranchId || '' })
    setDrawerOpen(true)
  }

  const openEdit = (student: StudentItem) => {
    setEditingStudent(student)
    setForm({
      branchId: student.branchId,
      classId: student.classId,
      fullname: student.fullname,
      regNumber: student.regNumber || '',
      email: student.email || '',
      phone: student.phone || '',
    })
    setDrawerOpen(true)
  }

  const openReassign = (student: StudentItem) => {
    setReassignStudentId(student.id)
    setReassignStudentName(student.fullname)
    setReassignBranchId(student.branchId)
    setReassignClassId('')
    setReassignDrawerOpen(true)
  }

  const openView = (student: StudentItem) => {
    setViewingStudent(student)
    setViewDrawerOpen(true)
  }

  const handleSave = () => {
    if (!form.fullname.trim() || !form.branchId || !form.classId) return

    if (editingStudent) {
      editMutation.mutate(
        { studentId: editingStudent.id, data: form },
        {
          onSuccess: () => {
            toast.success('Student updated')
            setDrawerOpen(false)
          },
          onError: (err: any) =>
            toast.error(err?.message || 'Failed to update'),
        },
      )
    } else {
      createMutation.mutate(form, {
        onSuccess: () => {
          toast.success('Student created')
          setDrawerOpen(false)
        },
        onError: (err: any) => toast.error(err?.message || 'Failed to create'),
      })
    }
  }

  const handleReassign = () => {
    if (!reassignClassId) return

    reassignMutation.mutate(
      {
        studentId: reassignStudentId,
        data: {
          classId: reassignClassId,
          branchId:
            reassignBranchId !== editingStudent?.branchId
              ? reassignBranchId
              : undefined,
        },
      },
      {
        onSuccess: () => {
          toast.success('Student reassigned')
          setReassignDrawerOpen(false)
        },
        onError: (err: any) =>
          toast.error(err?.message || 'Failed to reassign'),
      },
    )
  }

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return

    deleteMutation.mutate(selectedIds, {
      onSuccess: () => {
        toast.success(`${selectedIds.length} student(s) deleted`)
        setSelectedIds([])
        setDeleteConfirmOpen(false)
      },
      onError: (err: any) => {
        toast.error(err?.message || 'Failed to delete')
        setDeleteConfirmOpen(false)
      },
    })
  }

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id],
    )
  }

  const toggleSelectAll = () => {
    if (!filteredStudents) return
    if (selectedIds.length === filteredStudents.length) {
      setSelectedIds([])
    } else {
      setSelectedIds(filteredStudents.map((s: StudentItem) => s.id))
    }
  }

  const isPending = createMutation.isPending || editMutation.isPending

  const updateField = (field: keyof CreateStudentDTO, value: string) =>
    setForm((prev) => ({ ...prev, [field]: value }))

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Students</h1>
        <p className="text-muted-foreground text-sm">
          Manage student enrolment, class assignments, and transfers
        </p>
      </div>

      {/* Controls */}
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <CustomSelect
            fieldClassName="w-[260px]"
            value={filterBranchId}
            onValueChange={(value) => {
              setFilterBranchId(value)
              setFilterClassId('')
              setSelectedIds([])
            }}
            items={[
              { label: 'All branches', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
          <CustomSelect
            fieldClassName="w-[220px]"
            value={filterClassId}
            onValueChange={(value) => {
              setFilterClassId(value)
              setSelectedIds([])
            }}
            disabled={!filterBranchId}
            items={[
              { label: 'All classes', value: '' },
              ...(filterClasses || []).map((c: ClassItem) => ({
                label: c.name,
                value: c.id,
              })),
            ]}
          >
            <option value="">
              {filterBranchId ? 'All classes' : 'Select branch first'}
            </option>
            {filterClasses?.map((c: ClassItem) => (
              <option key={c.id} value={c.id}>
                {c.name}
              </option>
            ))}
          </CustomSelect>
          <Input
            placeholder="Search students..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="h-9 w-[200px]"
          />
        </div>
        <div className="flex items-center gap-2">
          {selectedIds.length > 0 && (
            <AlertDialog
              open={deleteConfirmOpen}
              onOpenChange={setDeleteConfirmOpen}
            >
              <AlertDialogTrigger asChild>
                <Button
                  variant="destructive"
                  size="sm"
                  disabled={deleteMutation.isPending}
                >
                  {deleteMutation.isPending
                    ? 'Deleting...'
                    : `Delete (${selectedIds.length})`}
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
                  <AlertDialogDescription>
                    This action cannot be undone. This will permanently delete{' '}
                    {selectedIds.length} student(s) and remove their data from
                    our servers.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleBatchDelete}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Delete Students
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          )}
          <Button onClick={openCreate}>+ Add Student</Button>
        </div>
      </div>

      {/* Table */}
      {isLoading ? (
        <div className="space-y-3">
          {Array.from({ length: 6 }).map((_, i) => (
            <Skeleton key={i} className="h-14 w-full" />
          ))}
        </div>
      ) : filteredStudents && filteredStudents.length > 0 ? (
        <div className="rounded-lg border bg-card overflow-hidden">
          <Table className="min-w-[1000px]">
            <TableHeader>
              <TableRow>
                <TableHead className="w-[40px]">
                  <input
                    type="checkbox"
                    checked={
                      filteredStudents.length > 0 &&
                      selectedIds.length === filteredStudents.length
                    }
                    onChange={toggleSelectAll}
                    className="size-4"
                  />
                </TableHead>
                <TableHead>Name</TableHead>
                <TableHead>Reg Number</TableHead>
                <TableHead>Class</TableHead>
                <TableHead>Branch</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredStudents.map((student: StudentItem) => (
                <TableRow
                  key={student.id}
                  data-state={
                    selectedIds.includes(student.id) ? 'selected' : undefined
                  }
                >
                  <TableCell>
                    <input
                      type="checkbox"
                      checked={selectedIds.includes(student.id)}
                      onChange={() => toggleSelect(student.id)}
                      className="size-4"
                    />
                  </TableCell>
                  <TableCell className="font-medium">
                    {student.fullname}
                  </TableCell>
                  <TableCell className="font-mono text-xs">
                    {student.regNumber || '—'}
                  </TableCell>
                  <TableCell>
                    <Badge variant="secondary">
                      {student.class?.name || '—'}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-muted-foreground text-sm">
                    {student.branch?.name || '—'}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={
                        student.status === 'ACTIVE' ? 'default' : 'destructive'
                      }
                    >
                      {student.status}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openView(student)}
                        title="View details"
                      >
                        <Eye className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openEdit(student)}
                        title="Edit student"
                      >
                        <Pencil className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openReassign(student)}
                        title="Reassign student"
                      >
                        <ArrowRightLeft className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
          <div className="text-muted-foreground border-t px-4 py-2 text-xs">
            {filteredStudents.length} student
            {filteredStudents.length !== 1 ? 's' : ''}
          </div>
        </div>
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground mb-4">
              {search
                ? 'No students match your search.'
                : 'No students yet. Enrol your first student.'}
            </p>
            {!search && (
              <Button variant="outline" onClick={openCreate}>
                + Add Student
              </Button>
            )}
          </CardContent>
        </Card>
      )}

      {/* Create/Edit Drawer */}
      <AppDrawer
        open={drawerOpen}
        onOpenChange={setDrawerOpen}
        title={editingStudent ? 'Edit Student' : 'New Student'}
        description={
          editingStudent
            ? 'Update student details.'
            : 'Fill in the details to enrol a new student.'
        }
        footer={
          <>
            <Button
              onClick={handleSave}
              disabled={
                isPending ||
                !form.fullname.trim() ||
                !form.branchId ||
                !form.classId
              }
            >
              {isPending
                ? 'Saving...'
                : editingStudent
                  ? 'Save Changes'
                  : 'Enrol Student'}
            </Button>
            <Button variant="outline" onClick={() => setDrawerOpen(false)}>
              Cancel
            </Button>
          </>
        }
      >
        <div className="space-y-2">
          <CustomSelect
            label={
              <>
                Branch <span className="text-destructive">*</span>
              </>
            }
            value={form.branchId}
            onValueChange={(value) => {
              updateField('branchId', value)
              updateField('classId', '')
            }}
            items={[
              { label: 'Select branch', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
        </div>

        <div className="space-y-2 mt-5">
          <CustomSelect
            label={
              <>
                Class <span className="text-destructive">*</span>
              </>
            }
            value={form.classId}
            onValueChange={(value) => updateField('classId', value)}
            disabled={!form.branchId}
            items={[
              {
                label: form.branchId ? 'Select class' : 'Select branch first',
                value: '',
              },
              ...(formClasses || []).map((c: ClassItem) => ({
                label: c.name,
                value: c.id,
              })),
            ]}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>
            Full Name <span className="text-destructive">*</span>
          </Label>
          <Input
            placeholder="Student full name"
            value={form.fullname}
            onChange={(e) => updateField('fullname', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>Registration Number</Label>
          <Input
            placeholder="e.g. STD/2026/001"
            value={form.regNumber}
            onChange={(e) => updateField('regNumber', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>Email</Label>
          <Input
            type="email"
            placeholder="Optional"
            value={form.email}
            onChange={(e) => updateField('email', e.target.value)}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>Phone</Label>
          <Input
            placeholder="Optional"
            value={form.phone}
            onChange={(e) => updateField('phone', e.target.value)}
          />
        </div>
      </AppDrawer>

      {/* View Drawer */}
      <AppDrawer
        open={viewDrawerOpen}
        onOpenChange={setViewDrawerOpen}
        title="Student Details"
        description={`Full information for ${viewingStudent?.fullname}`}
        footer={
          <Button variant="outline" onClick={() => setViewDrawerOpen(false)}>
            Close
          </Button>
        }
      >
        {viewingStudent && (
          <div className="space-y-6 pb-8">
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Full Name
              </p>
              <p className="text-base">{viewingStudent.fullname}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Registration Number
              </p>
              <p className="font-mono text-sm">
                {viewingStudent.regNumber || '—'}
              </p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Email Address
              </p>
              <p className="text-sm">{viewingStudent.email || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Phone Number
              </p>
              <p className="text-sm">{viewingStudent.phone || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Branch
              </p>
              <p className="text-sm">{viewingStudent.branch?.name || '—'}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">Class</p>
              <Badge variant="secondary">
                {viewingStudent.class?.name || '—'}
              </Badge>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Status
              </p>
              <Badge
                variant={
                  viewingStudent.status === 'ACTIVE' ? 'default' : 'destructive'
                }
              >
                {viewingStudent.status}
              </Badge>
            </div>
          </div>
        )}
      </AppDrawer>

      {/* Reassign Drawer */}
      <AppDrawer
        open={reassignDrawerOpen}
        onOpenChange={setReassignDrawerOpen}
        title="Reassign Student"
        description={`Move ${reassignStudentName} to a different class`}
        footer={
          <>
            <Button
              onClick={handleReassign}
              disabled={reassignMutation.isPending || !reassignClassId}
            >
              {reassignMutation.isPending ? 'Reassigning...' : 'Reassign'}
            </Button>
            <Button
              variant="outline"
              onClick={() => setReassignDrawerOpen(false)}
            >
              Cancel
            </Button>
          </>
        }
      >
        <div className="space-y-2">
          <CustomSelect
            label="Target Branch"
            value={reassignBranchId}
            onValueChange={(value) => {
              setReassignBranchId(value)
              setReassignClassId('')
            }}
            items={[
              { label: 'Select branch', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
        </div>

        <div className="space-y-2 mt-5">
          <CustomSelect
            label={
              <>
                New Class <span className="text-destructive">*</span>
              </>
            }
            value={reassignClassId}
            onValueChange={setReassignClassId}
            disabled={!reassignBranchId}
            items={[
              {
                label: reassignBranchId
                  ? 'Select new class'
                  : 'Select branch first',
                value: '',
              },
              ...(reassignClasses || []).map((c: ClassItem) => ({
                label: c.name,
                value: c.id,
              })),
            ]}
          />
        </div>
      </AppDrawer>
    </div>
  )
}

import { useState } from 'react'
import { createFileRoute } from '@tanstack/react-router'
import {
  useSubjectsQuery,
  useSubjectByIdQuery,
  useCreateSubjectMutation,
  useEditSubjectMutation,
  useDeleteSubjectsMutation,
  useAssignTeacherToSubjectMutation,
  useRemoveTeacherFromSubjectMutation,
} from '@/hooks/queries/subject.queries'
import { useBranchesQuery } from '@/hooks/queries/branch.queries'
import { useStaffsQuery } from '@/hooks/queries/staff.queries'
import { useClassesQuery } from '@/hooks/queries/class.queries'
import type {
  SubjectItem,
  CreateSubjectDTO,
  SubjectTeacherAssignment,
} from '@/hooks/api/subject.api'
import type { ClassItem } from '@/hooks/api/class.api'
import type { Branch, Staff } from '@repo/types'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent } from '@/components/ui/card'
import { Skeleton } from '@/components/ui/skeleton'
import { AppDrawer } from '@/components/ui/app-drawer'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog'
import { CustomSelect } from '@/components/ui/custom-select'
import { toast } from '@/lib/toast'
import { Pencil, Eye, BookOpen } from 'lucide-react'

export const Route = createFileRoute('/_authenticated/dashboard/subjects')({
  component: SubjectsPage,
})

const WEEKDAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

const emptyForm: CreateSubjectDTO = {
  branchId: '',
  name: '',
}

function SubjectsPage() {
  const [search, setSearch] = useState('')
  const [filterBranchId, setFilterBranchId] = useState('')
  const [selectedIds, setSelectedIds] = useState<Array<string>>([])

  // CRUD state
  const [drawerOpen, setDrawerOpen] = useState(false)
  const [editingSubject, setEditingSubject] = useState<SubjectItem | null>(null)
  const [form, setForm] = useState<CreateSubjectDTO>(emptyForm)

  const [viewDrawerOpen, setViewDrawerOpen] = useState(false)
  const [viewingSubject, setViewingSubject] = useState<SubjectItem | null>(null)

  // Assignment state
  const [assignDrawerOpen, setAssignDrawerOpen] = useState(false)
  const [managingSubjectId, setManagingSubjectId] = useState('')
  const [managingSubjectName, setManagingSubjectName] = useState('')
  const [managingBranchId, setManagingBranchId] = useState('')
  const [assignStaffId, setAssignStaffId] = useState('')
  const [assignClassId, setAssignClassId] = useState('')
  const [assignDays, setAssignDays] = useState<Array<string>>([])

  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false)

  // Queries
  const { data: branches } = useBranchesQuery()
  const { data: subjects, isLoading } = useSubjectsQuery(
    filterBranchId || undefined,
  )
  const { data: subjectDetail } = useSubjectByIdQuery(
    managingSubjectId || undefined,
  )
  const { data: branchStaffs } = useStaffsQuery(managingBranchId || undefined)
  const { data: branchClasses } = useClassesQuery(managingBranchId || undefined)

  // Mutations
  const createMutation = useCreateSubjectMutation()
  const editMutation = useEditSubjectMutation()
  const deleteMutation = useDeleteSubjectsMutation()
  const assignMutation = useAssignTeacherToSubjectMutation()
  const removeMutation = useRemoveTeacherFromSubjectMutation()

  const filteredSubjects = subjects?.filter((s: SubjectItem) =>
    s.name.toLowerCase().includes(search.toLowerCase()),
  )

  const openCreate = () => {
    setEditingSubject(null)
    setForm({ ...emptyForm, branchId: filterBranchId || '' })
    setDrawerOpen(true)
  }

  const openEdit = (subject: SubjectItem) => {
    setEditingSubject(subject)
    setForm({ branchId: subject.branchId, name: subject.name })
    setDrawerOpen(true)
  }

  const openAssignments = (subject: SubjectItem) => {
    setManagingSubjectId(subject.id)
    setManagingSubjectName(subject.name)
    setManagingBranchId(subject.branchId)
    setAssignStaffId('')
    setAssignClassId('')
    setAssignDays([])
    setAssignDrawerOpen(true)
  }

  const openView = (subject: SubjectItem) => {
    setViewingSubject(subject)
    setViewDrawerOpen(true)
  }

  const handleSave = () => {
    if (!form.name.trim() || !form.branchId) return

    if (editingSubject) {
      editMutation.mutate(
        { subjectId: editingSubject.id, data: form },
        {
          onSuccess: () => {
            toast.success('Subject updated')
            setDrawerOpen(false)
          },
          onError: (err: any) =>
            toast.error(err?.message || 'Failed to update'),
        },
      )
    } else {
      createMutation.mutate(form, {
        onSuccess: () => {
          toast.success('Subject created')
          setDrawerOpen(false)
        },
        onError: (err: any) => toast.error(err?.message || 'Failed to create'),
      })
    }
  }

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return

    deleteMutation.mutate(selectedIds, {
      onSuccess: () => {
        toast.success(`${selectedIds.length} subject(s) deleted`)
        setSelectedIds([])
        setDeleteConfirmOpen(false)
      },
      onError: (err: any) => {
        toast.error(err?.message || 'Failed to delete')
        setDeleteConfirmOpen(false)
      },
    })
  }

  const handleAssignTeacher = () => {
    if (!assignStaffId || !assignClassId || assignDays.length === 0) return

    assignMutation.mutate(
      {
        subjectId: managingSubjectId,
        data: {
          staffId: assignStaffId,
          classId: assignClassId,
          days: assignDays.join(', '),
        },
      },
      {
        onSuccess: () => {
          toast.success('Teacher assigned')
          setAssignStaffId('')
          setAssignClassId('')
          setAssignDays([])
        },
        onError: (err: any) => toast.error(err?.message || 'Failed to assign'),
      },
    )
  }

  const handleRemoveAssignment = (assignmentId: string) => {
    removeMutation.mutate(
      { subjectId: managingSubjectId, assignmentId },
      {
        onSuccess: () => toast.success('Assignment removed'),
        onError: (err: any) => toast.error(err?.message || 'Failed to remove'),
      },
    )
  }

  const toggleDay = (day: string) => {
    setAssignDays((prev) =>
      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day],
    )
  }

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id],
    )
  }

  const toggleSelectAll = () => {
    if (!filteredSubjects) return
    if (selectedIds.length === filteredSubjects.length) {
      setSelectedIds([])
    } else {
      setSelectedIds(filteredSubjects.map((s: SubjectItem) => s.id))
    }
  }

  const isPending = createMutation.isPending || editMutation.isPending

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Subjects</h1>
        <p className="text-muted-foreground text-sm">
          Manage subjects and assign teachers to classes
        </p>
      </div>

      {/* Controls */}
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <CustomSelect
            fieldClassName="w-[260px]"
            value={filterBranchId}
            onValueChange={(value) => {
              setFilterBranchId(value)
              setSelectedIds([])
            }}
            items={[
              { label: 'All branches', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
          <Input
            placeholder="Search subjects..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="h-9 w-[220px]"
          />
        </div>
        <div className="flex items-center gap-2">
          {selectedIds.length > 0 && (
            <AlertDialog
              open={deleteConfirmOpen}
              onOpenChange={setDeleteConfirmOpen}
            >
              <AlertDialogTrigger asChild>
                <Button
                  variant="destructive"
                  size="sm"
                  disabled={deleteMutation.isPending}
                >
                  {deleteMutation.isPending
                    ? 'Deleting...'
                    : `Delete (${selectedIds.length})`}
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
                  <AlertDialogDescription>
                    This will permanently delete {selectedIds.length} subject(s)
                    and remove associated data from our servers.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleBatchDelete}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Delete Subjects
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          )}
          <Button onClick={openCreate}>+ Add Subject</Button>
        </div>
      </div>

      {/* Table */}
      {isLoading ? (
        <div className="space-y-3">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-14 w-full" />
          ))}
        </div>
      ) : filteredSubjects && filteredSubjects.length > 0 ? (
        <div className="rounded-lg border bg-card overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[40px]">
                  <input
                    type="checkbox"
                    checked={
                      filteredSubjects.length > 0 &&
                      selectedIds.length === filteredSubjects.length
                    }
                    onChange={toggleSelectAll}
                    className="size-4"
                  />
                </TableHead>
                <TableHead>Name</TableHead>
                <TableHead>Branch</TableHead>
                <TableHead className="text-center">Assigned Teachers</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredSubjects.map((subject: SubjectItem) => (
                <TableRow
                  key={subject.id}
                  data-state={
                    selectedIds.includes(subject.id) ? 'selected' : undefined
                  }
                >
                  <TableCell>
                    <input
                      type="checkbox"
                      checked={selectedIds.includes(subject.id)}
                      onChange={() => toggleSelect(subject.id)}
                      className="size-4"
                    />
                  </TableCell>
                  <TableCell className="font-medium">{subject.name}</TableCell>
                  <TableCell className="text-muted-foreground text-sm">
                    {subject.branch?.name || '—'}
                  </TableCell>
                  <TableCell className="text-center">
                    <Badge variant="secondary">
                      {subject._count?.subjectTeachers ?? 0}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openView(subject)}
                        title="View details"
                      >
                        <Eye className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openEdit(subject)}
                        title="Edit subject"
                      >
                        <Pencil className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="size-8"
                        onClick={() => openAssignments(subject)}
                        title="Assign Teachers"
                      >
                        <BookOpen className="size-4 text-muted-foreground hover:text-foreground" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
          <div className="text-muted-foreground border-t px-4 py-2 text-xs">
            {filteredSubjects.length} subject
            {filteredSubjects.length !== 1 ? 's' : ''}
          </div>
        </div>
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground mb-4">
              {search
                ? 'No subjects match your search.'
                : 'No subjects yet. Create your first subject.'}
            </p>
            {!search && (
              <Button variant="outline" onClick={openCreate}>
                + Add Subject
              </Button>
            )}
          </CardContent>
        </Card>
      )}

      {/* Create/Edit Drawer */}
      <AppDrawer
        open={drawerOpen}
        onOpenChange={setDrawerOpen}
        title={editingSubject ? 'Edit Subject' : 'New Subject'}
        description={
          editingSubject
            ? 'Update subject details.'
            : 'Create a new subject for a branch.'
        }
        footer={
          <>
            <Button
              onClick={handleSave}
              disabled={isPending || !form.name.trim() || !form.branchId}
            >
              {isPending
                ? 'Saving...'
                : editingSubject
                  ? 'Save Changes'
                  : 'Create Subject'}
            </Button>
            <Button variant="outline" onClick={() => setDrawerOpen(false)}>
              Cancel
            </Button>
          </>
        }
      >
        <div className="space-y-2">
          <CustomSelect
            label={
              <>
                Branch <span className="text-destructive">*</span>
              </>
            }
            value={form.branchId}
            onValueChange={(value) =>
              setForm((prev) => ({ ...prev, branchId: value }))
            }
            items={[
              { label: 'Select branch', value: '' },
              ...(branches || []).map((b: Branch) => ({
                label: b.name,
                value: b.id,
              })),
            ]}
          />
        </div>

        <div className="space-y-2 mt-5">
          <Label>
            Name <span className="text-destructive">*</span>
          </Label>
          <Input
            placeholder="e.g. Mathematics"
            value={form.name}
            onChange={(e) =>
              setForm((prev) => ({ ...prev, name: e.target.value }))
            }
          />
        </div>
      </AppDrawer>

      {/* Teacher Assignment Drawer */}
      <AppDrawer
        open={assignDrawerOpen}
        onOpenChange={setAssignDrawerOpen}
        title="Teacher Assignments"
        description={`Manage teacher assignments for ${managingSubjectName}`}
        footer={
          <Button variant="outline" onClick={() => setAssignDrawerOpen(false)}>
            Close
          </Button>
        }
      >
        <div className="space-y-6">
          {/* Assign form */}
          <div className="space-y-4 rounded-md border p-4">
            <p className="text-sm font-medium">Assign a Teacher</p>

            <div className="space-y-2">
              <CustomSelect
                label="Teacher"
                value={assignStaffId}
                onValueChange={setAssignStaffId}
                items={[
                  { label: 'Select teacher', value: '' },
                  ...(branchStaffs || []).map((s: Staff) => ({
                    label: s.fullname,
                    value: s.id,
                  })),
                ]}
              />
            </div>

            <div className="space-y-2">
              <CustomSelect
                label="Class"
                value={assignClassId}
                onValueChange={setAssignClassId}
                items={[
                  { label: 'Select class', value: '' },
                  ...(branchClasses || []).map((c: ClassItem) => ({
                    label: c.name,
                    value: c.id,
                  })),
                ]}
              />
            </div>

            <div className="space-y-2">
              <Label>Days</Label>
              <div className="flex flex-wrap gap-2">
                {WEEKDAYS.map((day) => (
                  <button
                    key={day}
                    type="button"
                    onClick={() => toggleDay(day)}
                    className={`rounded-md border px-3 py-1.5 text-xs font-medium transition-colors ${
                      assignDays.includes(day)
                        ? 'border-primary bg-primary text-primary-foreground'
                        : 'hover:bg-muted'
                    }`}
                  >
                    {day.slice(0, 3)}
                  </button>
                ))}
              </div>
            </div>

            <Button
              size="sm"
              className="w-full"
              onClick={handleAssignTeacher}
              disabled={
                assignMutation.isPending ||
                !assignStaffId ||
                !assignClassId ||
                assignDays.length === 0
              }
            >
              {assignMutation.isPending ? 'Assigning...' : 'Assign Teacher'}
            </Button>
          </div>

          {/* Current assigned teachers */}
          <div className="space-y-2">
            <p className="text-sm font-medium">
              Current Assigned Teachers (
              {subjectDetail?.subjectTeachers?.length ?? 0})
            </p>

            {subjectDetail?.subjectTeachers &&
            subjectDetail.subjectTeachers.length > 0 ? (
              <div className="space-y-2">
                {subjectDetail.subjectTeachers.map(
                  (assignment: SubjectTeacherAssignment) => (
                    <div
                      key={assignment.id}
                      className="flex items-start justify-between rounded-md border px-3 py-2"
                    >
                      <div className="space-y-0.5">
                        <div className="text-sm font-medium">
                          {assignment.teacher.fullname}
                        </div>
                        <div className="text-muted-foreground text-xs">
                          {assignment.class.name}
                          {assignment.class.level &&
                            ` · ${assignment.class.level}`}
                        </div>
                        <div className="flex flex-wrap gap-1 pt-1">
                          {assignment.days.split(',').map((day) => (
                            <Badge
                              key={day}
                              variant="outline"
                              className="text-[10px] px-1.5 py-0"
                            >
                              {day.trim().slice(0, 3)}
                            </Badge>
                          ))}
                        </div>
                      </div>
                      <Button
                        variant="ghost"
                        size="sm"
                        className="h-7 text-xs text-destructive hover:text-destructive"
                        onClick={() => handleRemoveAssignment(assignment.id)}
                        disabled={removeMutation.isPending}
                      >
                        Remove
                      </Button>
                    </div>
                  ),
                )}
              </div>
            ) : (
              <p className="text-muted-foreground rounded-md border border-dashed px-3 py-6 text-center text-sm">
                No teacher assignments yet.
              </p>
            )}
          </div>
        </div>
      </AppDrawer>

      {/* View Drawer */}
      <AppDrawer
        open={viewDrawerOpen}
        onOpenChange={setViewDrawerOpen}
        title="Subject Details"
        description={`Full information for ${viewingSubject?.name}`}
        footer={
          <Button variant="outline" onClick={() => setViewDrawerOpen(false)}>
            Close
          </Button>
        }
      >
        {viewingSubject && (
          <div className="space-y-6 pb-8">
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Subject Name
              </p>
              <p className="text-base font-medium">{viewingSubject.name}</p>
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-muted-foreground">
                Branch
              </p>
              <p className="text-sm">{viewingSubject.branch?.name || '—'}</p>
            </div>
            <div className="space-y-1 rounded-lg border p-3">
              <p className="text-xs font-medium text-muted-foreground">
                Active Assigned Teachers
              </p>
              <p className="text-2xl font-bold">
                {viewingSubject._count?.subjectTeachers ?? 0}
              </p>
            </div>
          </div>
        )}
      </AppDrawer>
    </div>
  )
}

import { Outlet, createFileRoute, redirect } from '@tanstack/react-router'
import { useEffect, useRef } from 'react'
import { useAuthStore } from '@repo/api'
import { getLoginUrl, isLocalDev } from '@/lib/subdomain'
import { toast } from '@/lib/toast'

export const Route = createFileRoute('/_authenticated')({
  beforeLoad: ({ context, location }) => {
    if (!context.auth?.isAuthenticated) {
      const loginUrl = getLoginUrl()
      if (!isLocalDev()) {
        // Full cross-origin redirect to login portal
        window.location.href = loginUrl
        // Prevent further routing while redirect happens
        throw redirect({ to: '/login' })
      } else {
        throw redirect({
          to: '/login',
          search: {
            redirect: location.href,
          },
        })
      }
    }
  },
  component: RouteComponent,
})

function AuthGuard({ children }: { children: React.ReactNode }) {
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated)
  const hasRedirected = useRef(false)

  useEffect(() => {
    if (!isAuthenticated && !hasRedirected.current) {
      hasRedirected.current = true

      toast.warning('Session expired', {
        description: 'You have been logged out. Redirecting to login...',
      })

      setTimeout(() => {
        const loginUrl = getLoginUrl()
        if (isLocalDev()) {
          window.location.href = '/login'
        } else {
          window.location.href = loginUrl
        }
      }, 2000)
    }
  }, [isAuthenticated])

  if (!isAuthenticated) {
    return null
  }

  return <>{children}</>
}

function RouteComponent() {
  return (
    <AuthGuard>
      <Outlet />
    </AuthGuard>
  )
}

